package main

import (
	"sort"
)

type UnionFind struct {
	parent []int
	minNode []int
}

func NewUnionFind(size int) *UnionFind {
	parent := make([]int, size+1)
	minNode := make([]int, size+1)
	for i := range parent {
		parent[i] = i
		minNode[i] = i
	}
	return &UnionFind{parent, minNode}
}

func (uf *UnionFind) Find(x int) int {
	for uf.parent[x] != x {
		uf.parent[x] = uf.parent[uf.parent[x]]
		x = uf.parent[x]
	}
	return x
}

func (uf *UnionFind) Union(x, y int) {
	xRoot := uf.Find(x)
	yRoot := uf.Find(y)
	if xRoot == yRoot {
		return
	}
	if xRoot < yRoot {
		uf.parent[yRoot] = xRoot
		if uf.minNode[yRoot] < uf.minNode[xRoot] {
			uf.minNode[xRoot] = uf.minNode[yRoot]
		}
	} else {
		uf.parent[xRoot] = yRoot
		if uf.minNode[xRoot] < uf.minNode[yRoot] {
			uf.minNode[yRoot] = uf.minNode[xRoot]
		}
	}
}

func solve(c int64, connections [][]int64, queries [][]int64) []int64 {
	uf := NewUnionFind(int(c))
	for _, conn := range connections {
		u, v := int(conn[0]), int(conn[1])
		uf.Union(u, v)
	}

	online := make([]bool, c+1)
	for i := 1; i <= int(c); i++ {
		online[i] = true
	}

	// Precompute for each root, a sorted list of nodes in the component
	componentNodes := make(map[int][]int)
	for i := 1; i <= int(c); i++ {
		root := uf.Find(i)
		componentNodes[root] = append(componentNodes[root], i)
	}

	// Sort each component's nodes
	for root := range componentNodes {
		sort.Ints(componentNodes[root])
	}

	res := make([]int64, 0)
	for _, query := range queries {
		typeQ, x := query[0], int(query[1])
		if typeQ == 1 {
			root := uf.Find(x)
			if online[x] {
				res = append(res, int64(x))
			} else {
				found := -1
				for _, node := range componentNodes[root] {
					if online[node] {
						found = node
						break
					}
				}
				res = append(res, int64(found))
			}
		} else if typeQ == 2 {
			online[x] = false
		}
	}
	return res
}
